description:
Implement the main render pipeline entry point - PromptWorld::render_prompt_value. This is the core rendering logic.

Location: crates/baml-bridge/src/prompt/world.rs

```rust
impl PromptWorld {
    /// Main rendering entry point
    pub fn render_prompt_value(
        &self,
        pv: &PromptValue,
        style_override: Option<&str>,
    ) -> RenderResult {
        // 1. Determine effective style
        let style = self.resolve_style(pv, style_override);

        // 2. Try renderers in precedence order
        let result = self.try_render_chain(pv, &style)?;

        // 3. Apply budget truncation (NOT an error)
        let truncated = self.apply_budget_truncation(result, pv);

        Ok(truncated)
    }

    fn resolve_style(&self, pv: &PromptValue, override_style: Option<&str>) -> String {
        // Precedence:
        // 1. Call-site override (style_override param)
        // 2. Field override style (pv.override_renderer)
        // 3. Default: 'default'

        if let Some(style) = override_style {
            return style.to_string();
        }

        if let Some(RendererOverride::Style { style }) = &pv.override_renderer {
            return style.to_string();
        }

        'default'.to_string()
    }

    fn try_render_chain(&self, pv: &PromptValue, style: &str) -> RenderResult {
        // Try in order:
        // 1. Per-field override renderer (if matches style)
        if let Some(result) = self.try_field_override(pv, style)? {
            return Ok(result);
        }

        // 2. Type-level renderer
        if let Some(result) = self.try_type_renderer(pv, style)? {
            return Ok(result);
        }

        // 3. Built-in format styles (json|yaml|toon)
        if let Some(result) = self.try_builtin_style(pv, style)? {
            return Ok(result);
        }

        // 4. Structural fallback (default behavior, not recovery)
        Ok(self.render_structural(pv))
    }
}
```

Key: this is strict-only. Any error in the chain returns Err immediately. Budgets truncate, they don't error.
